def is_prime(n: int) -> bool:
    """Return True if n is a prime number, otherwise False."""
    if n < 2:
        return False
    if n in (2, 3):
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False

    i = 5
    step = 2  # checks 6k±1
    while i * i <= n:
        if n % i == 0:
            return False
        i += step
        step = 6 - step
    return True
